 24→function formatTokens(tokens: number) {
 25→	if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}M`;
 26→	if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}K`;
 27→	return tokens.toString();
 28→}
