166→	}
167→
168→	return (
169→		<div className="px-8 py-6">
170→			<PageHeader
171→				title="Projects"
172→				description="Analyze project activity and team investment"
173→				actions={
174→					<DatePicker
175→						startDate={startDate}
176→						endDate={endDate}
177→						onStartDateChange={setStartDate}
178→						onEndDateChange={setEndDate}
179→					/>
180→				}
181→			/>
182→
183→			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-6 gap-6 mb-8">
184→				<StatCard
185→					title="Active Projects"
186→					value={totalProjects}
187→					icon={FolderKanban}
188→					iconColor="text-blue-600"
189→				/>
190→				<StatCard
191→					title="Total Sessions"
192→					value={totalSessions.toLocaleString()}
193→					icon={TrendingUp}
194→					iconColor="text-green-600"
195→				/>
196→				<StatCard
197→					title="Total Time"
198→					value={totalHours.toFixed(0)}
199→					icon={Clock}
200→					iconColor="text-purple-600"
201→				/>
202→				<StatCard
